INSERT INTO testimonials (author_name, content, order_index, is_active) VALUES
('שרה כהן', 'עבדתי עם רוחי בשזירת זר הכלה שלי והתוצאה הייתה פשוט מדהימה! היא הקשיבה בדיוק למה שרציתי והצליחה ליצור משהו שעבר את כל הציפיות. הזר היה מושלם, טרי ומרהיב. כל האורחים התפעלו ואני ממליצה עליה בחום!', 1, true),
('מרים לוי', 'רוחי עיצבה לנו את כל האירוסין והחתונה - מהזרים ועד לעיצוב הכיסאות. הכל היה מושלם! היא בעלת טעם מעולה, יצירתית ומקצועית. העבודה שלה הפכה את האירוע שלנו למשהו מיוחד במינו. תודה רבה!', 2, true),
('דינה שטרן', 'זר האירוסין שקיבלתי מרוחי היה פשוט חלומי! היא הבינה בדיוק את הסגנון שרציתי ויצרה יצירת אמנות אמיתית. הפרחים היו טריים, העיצוב מיוחד והשירות היה מעולה. ממליצה בחום לכל כלה!', 3, true);